@app.route('/dashboard')
def dashboard():
    # Get query parameters
    name = request.args.get('name', 'Guest')
    bio = request.args.get('bio', '')
    location = request.args.get('location', '')
    status = request.args.get('status', '')
    
    # Escape name and location (no formatting support, just plain text)
    # These will be auto-escaped by Jinja2's {{ }} syntax
    
    # For bio and status, we convert basic formatting markers to HTML
    # The convert_basic_formatting function escapes first, then applies formatting
    # We wrap the result in Markup so Jinja2 knows it's already safe
    from markupsafe import Markup
    
    bio_html = Markup(convert_basic_formatting(bio)) if bio else ''
    status_html = Markup(convert_basic_formatting(status)) if status else ''
    
    # Get the initial for the avatar (escaped name's first character)
    escaped_name = str(escape(name))
    initial = escaped_name[0].upper() if escaped_name else 'G'
    
    return render_template_string(
        DASHBOARD_TEMPLATE,
        name=name,          # Auto-escaped by Jinja2 {{ name }}
        location=location,  # Auto-escaped by Jinja2 {{ location }}
        bio_html=bio_html,  # Pre-sanitized Markup object
        status_html=status_html,  # Pre-sanitized Markup object
        initial=initial     # Single character, already derived from escaped name
    )


